const lead = Array.isArray($('Fetch Lead and Subscription').first().json)
  ? $('Fetch Lead and Subscription').first().json[0]
  : $('Fetch Lead and Subscription').first().json;

const sub = Array.isArray($('Fetch Current Subscription').first().json)
  ? $('Fetch Current Subscription').first().json[0]
  : $('Fetch Current Subscription').first().json;

const triggerType = $('Webhook or Workflow Input').first().json.trigger_type;
const callCount = $('Webhook or Workflow Input').first().json.call_count || 0;

// Niche-based upsell pricing
// These prices are placeholders — the human sets actual Stripe price IDs
const upsellOffers = {
  plateau: {
    subject: 'Let\'s get more calls coming in for ' + lead.business_name,
    headline: 'Add our Local SEO Pack',
    body: `Your site has been live for a while but calls have been slow. Our Local SEO Pack adds Google Business Profile optimisation, monthly Google Posts, and citation building. Most trades businesses see a 2–3x increase in calls within 60 days.`,
    cta_text: 'Add SEO Pack',
    cta_url: 'https://mysitehq.com.au/upgrade/seo-pack?lead_id=' + lead.lead_id,
    price_display: 'Add from $49/mo'
  },
  milestone: {
    subject: lead.business_name + ' is getting calls — ready to scale?',
    headline: 'You\'re getting enquiries. Here\'s how to get more.',
    body: `You\'ve had ${callCount} tracked calls this month — that\'s strong. Our Growth Plan adds Google Ads management, targeting your most profitable service-suburb combinations. Customers on this plan average 3x the call volume within 90 days.`,
    cta_text: 'See Growth Plan',
    cta_url: 'https://mysitehq.com.au/upgrade/growth?lead_id=' + lead.lead_id,
    price_display: 'From $149/mo'
  },
  renewal: {
    subject: 'Save 20% on your annual plan — limited time',
    headline: 'Prepay for a year and save 20%',
    body: `You\'ve been on monthly billing. Switch to annual and save 20% — that\'s $${Math.round((sub ? sub.amount_cents : 5900) * 12 * 0.2 / 100)} back in your pocket. Annual plans also get priority support and a free site refresh.`,
    cta_text: 'Switch to annual',
    cta_url: 'https://mysitehq.com.au/upgrade/annual?lead_id=' + lead.lead_id,
    price_display: '20% off annual billing'
  }
};

const offer = upsellOffers[triggerType] || upsellOffers.plateau;

const html = `<!DOCTYPE html>
<html>
<body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:24px;">
<h1 style="color:#1D4ED8;">${offer.headline}</h1>
<p>Hi,</p>
<p>${offer.body}</p>
<p><a href="${offer.cta_url}" style="background:#1D4ED8;color:#fff;padding:14px 28px;border-radius:6px;text-decoration:none;display:inline-block;font-size:16px;">${offer.cta_text} — ${offer.price_display}</a></p>
<p>Questions? Just reply to this email.</p>
<p>— Preview Factory</p>
</body>
</html>`;

return [{
  json: {
    lead_id: lead.lead_id,
    business_name: lead.business_name,
    email: lead.email,
    phone: lead.phone,
    trigger_type: triggerType,
    offer_subject: offer.subject,
    offer_html: html,
    offer_cta_url: offer.cta_url,
    sms_text: 'Preview Factory: ' + offer.headline + ' — ' + offer.price_display + '. Details: ' + offer.cta_url
  }
}];
